const GROUP_MAP = {
  '120363426390515923@g.us': { context: 'angelfly', label: 'Angel Fly' },
  '120363420996892188@g.us': { context: 'garlic',   label: 'Garlic N Lemon' },
  '120363422948599063@g.us': { context: 'ernesto',  label: 'Ernesto' },
};

const raw  = $input.first().json;
const body = raw.body || raw;

// Debug: capture all keys at every level
const debugKeys = Object.keys(body || {}).join(', ');
const debugData = body?.data ? Object.keys(body.data).join(', ') : 'n/a';

// --- Message text (try all common paths) ---
const messageText =
  body?.text ||
  body?.message?.text ||
  body?.message?.body ||
  body?.data?.text ||
  body?.data?.message?.text ||
  body?.data?.message?.body ||
  '';

// --- Sender name ---
const senderName =
  body?.senderName ||
  body?.message?.senderName ||
  body?.data?.senderName ||
  body?.sender?.pushname ||
  'Unknown';

// --- Chat ID (try every possible field name) ---
const chatId =
  body?.chatid ||
  body?.chatId ||
  body?.wa_chatid ||
  body?.waChatId ||
  body?.remoteJid ||
  body?.id ||
  body?.data?.chatid ||
  body?.data?.chatId ||
  body?.data?.wa_chatid ||
  body?.data?.remoteJid ||
  body?.message?.chatid ||
  body?.message?.chatId ||
  body?.message?.remoteJid ||
  '';

const groupInfo = GROUP_MAP[chatId] || { context: 'unknown', label: 'Unknown' };

return [{ json: {
  rawMessage: messageText,
  cleanMessage: messageText.replace(/@\w+/g, '').trim(),
  senderName,
  chatId,
  waChatId: chatId,
  groupContext: groupInfo.context,
  groupLabel: groupInfo.label,
  timestamp: new Date().toISOString(),
  _debug_keys: debugKeys,
  _debug_data_keys: debugData
}}];

const inputData = $input.first().json;
let responseText = '';
if (inputData?.message?.content) {
  responseText = inputData.message.content;
} else if (inputData?.choices?.[0]?.message?.content) {
  responseText = inputData.choices[0].message.content;
} else if (typeof inputData?.text === 'string') {
  responseText = inputData.text;
} else {
  responseText = JSON.stringify(inputData);
}

let parsed;
try {
  const clean = responseText.replace(/```(?:json)?/g, '').replace(/```/g, '').trim();
  const match = clean.match(/({[\s\S]*})/);
  parsed = JSON.parse(match ? match[1] : clean);
} catch (e) {
  parsed = { intent: 'none', reply: 'Não consegui processar isso. Pode reformular?', entity: {} };
}

const entity = parsed.entity || {};
const pm = $('Check Personality Command').first().json;

// Get known projects to validate project_id
let knownProjects = [];
try {
  const ctx = $('Build Context').first().json;
  knownProjects = JSON.parse(ctx.projectsList || '[]');
} catch(e) {}

let intent = parsed.intent || 'none';

// Validate project_id against known projects
if (intent === 'create_task') {
  if (!entity.title) {
    intent = 'none';
    parsed.reply = 'Preciso de mais detalhes para criar a tarefa. Qual é o título?';
  } else if (entity.project_id) {
    // Check that project_id actually exists in our fetched list
    const validProject = knownProjects.find(p => String(p.id) === String(entity.project_id));
    if (!validProject) {
      // Project not found — try fuzzy match by name
      const targetName = (entity.project_name || '').toLowerCase();
      const fuzzy = knownProjects.find(p => p.name.toLowerCase().includes(targetName) || targetName.includes(p.name.toLowerCase()));
      if (fuzzy) {
        entity.project_id = fuzzy.id;
        entity.project_name = fuzzy.name;
      } else {
        // No match — create without project_id, warn user
        entity.project_id = null;
        parsed.reply = `⚠️ Projeto "${entity.project_name || 'solicitado'}" não encontrado no Cockpit. Crie o projeto primeiro e tente novamente. A tarefa *não* foi criada.`;
        intent = 'none';
      }
    }
  }
}

if (intent === 'create_ticket' && !entity.subject) {
  intent = 'none';
  parsed.reply = 'Preciso de mais detalhes para o ticket. Qual é o assunto?';
}

const replyTarget = pm.waChatId || pm.chatId || '120363426390515923@g.us';
const clientName = entity.client_name || (pm.groupContext === 'garlic' ? 'Garlic N Lemon' : pm.groupContext === 'ernesto' ? 'Ernesto' : 'Angel Fly');

return [{ json: {
  intent,
  entity,
  title: entity.title || entity.subject || '',
  description: entity.description || '',
  priority: entity.priority || 'medium',
  project_id: entity.project_id || null,
  project_name: entity.project_name || '',
  subject: entity.subject || entity.title || '',
  category: entity.category || 'question',
  client_name: clientName,
  amount: entity.amount || 0,
  reply: parsed.reply || 'Entendido!',
  senderName: pm.senderName,
  chatId: pm.chatId,
  waChatId: replyTarget,
  groupContext: pm.groupContext,
  groupLabel: pm.groupLabel
}}];

const msg = $input.first().json.cleanMessage.toLowerCase();

// Detect personality adjustment commands
const isPersonalityCmd = (
  (msg.includes('humor') || msg.includes('seriedade') || msg.includes('sério') || msg.includes('serio') || msg.includes('personalidade'))
  && (msg.includes('aument') || msg.includes('diminui') || msg.includes('reduz') || msg.includes('coloca') || msg.includes('%') || /\d+/.test(msg))
);

return [{ json: { ...($input.first().json), isPersonalityCmd } }];

const staticData = $getWorkflowStaticData('global');
const msg = $input.first().json.cleanMessage.toLowerCase();

// Current level (0 = serious, 100 = very funny)
let currentLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;

// Extract percentage from message
const pctMatch = msg.match(/(\d+)\s*%/);
const numMatch = msg.match(/(\d+)/);
const pct = pctMatch ? parseInt(pctMatch[1]) : (numMatch ? parseInt(numMatch[1]) : 20);

let newLevel = currentLevel;
let action = '';

if (msg.includes('aument') || msg.includes('mais')) {
  newLevel = Math.min(100, currentLevel + pct);
  action = 'aumentado';
} else if (msg.includes('diminui') || msg.includes('reduz') || msg.includes('menos')) {
  newLevel = Math.max(0, currentLevel - pct);
  action = 'reduzido';
} else if (msg.includes('coloca') || msg.includes('define') || msg.includes('set')) {
  newLevel = Math.min(100, Math.max(0, pct));
  action = 'definido para';
}

staticData.humorLevel = newLevel;

const levelDesc = newLevel <= 20 ? 'muito sério' : newLevel <= 40 ? 'sério' : newLevel <= 60 ? 'equilibrado' : newLevel <= 80 ? 'descontraído' : 'bem humorado';

return [{ json: {
  waChatId: $input.first().json.waChatId,
  reply: `✅ Nível de humor ${action}: ${newLevel}% (${levelDesc}). Ajuste aplicado.`
}}];

const staticData = $getWorkflowStaticData('global');
const humorLevel = staticData.humorLevel !== undefined ? staticData.humorLevel : 30;

const pm = $('Check Personality Command').first().json;

// ── Chat History ──────────────────────────────────────────────────────────
let historyText = '';
try {
  const historyData = $('Get Chat History').first().json;
  const msgs = Array.isArray(historyData) ? historyData : (historyData?.messages || []);

  // Build readable text block (chronological order - reverse since API returns newest first)
  const lines = [...msgs]
    .filter(m => {
      const txt = m.text || m.body || m.content?.conversation || m.content?.extendedTextMessage?.text || '';
      return txt && txt.trim().length > 0;
    })
    .slice(0, 50)
    .reverse() // oldest → newest
    .map(m => {
      const txt = m.text || m.body || m.content?.conversation || m.content?.extendedTextMessage?.text || '';
      const name = m.fromMe ? 'ANGELFLY (Jarvis)' : (m.senderName || 'Membro');
      return `[${name}]: ${txt.trim()}`;
    });

  historyText = lines.length > 0
    ? lines.join('\n')
    : '(sem histórico disponível)';
} catch(e) {
  historyText = '(erro ao carregar histórico: ' + e.message + ')';
}

// ── Projects List ──────────────────────────────────────────────────────────
let projectsList = [];
let projectsRef = '  (nenhum projeto cadastrado ainda)';
try {
  const projData = $('Fetch Projects').first().json;
  const projs = Array.isArray(projData) ? projData : [];
  projectsList = projs
    .filter(p => p.status === 'active')
    .map(p => ({ id: p.id, name: p.name, client_name: p.client_name || '' }));
  if (projectsList.length > 0) {
    projectsRef = projectsList.map(p => `  - id=${p.id} | "${p.name}" | cliente: "${p.client_name}"`).join('\n');
  }
} catch(e) { projectsList = []; }

// ── Humor description ──────────────────────────────────────────────────────
const humorDesc = humorLevel <= 20 ? 'muito sério e formal, sem humor'
  : humorLevel <= 40 ? 'profissional com leveza ocasional'
  : humorLevel <= 60 ? 'equilibrado entre profissional e descontraído'
  : humorLevel <= 80 ? 'descontraído com bom humor moderado'
  : 'bem humorado e leve, com humor frequente';

return [{ json: {
  ...pm,
  messageText: pm.cleanMessage || pm.rawMessage || '',
  humorLevel,
  humorDesc,
  projectsRef,
  projectsList: JSON.stringify(projectsList),
  historyText,
} }];
